import os
from clickhouse_driver import Client
from datetime import date, timedelta


class AnalyticsService:
    def __init__(self):
        self.client = Client(
            host=os.environ.get('CLICKHOUSE_HOST', 'localhost'),
            port=int(os.environ.get('CLICKHOUSE_PORT', '9000')),
            database=os.environ.get('CLICKHOUSE_DB', 'analytics')
        )

    def daily_active_users(self, start: date, end: date) -> list[dict]:
        rows = self.client.execute(
            'SELECT toDate(timestamp) as day, uniqExact(user_id) as users '
            'FROM events WHERE day BETWEEN %(start)s AND %(end)s '
            'GROUP BY day ORDER BY day',
            {'start': start, 'end': end}
        )
        return [{'date': str(r[0]), 'users': r[1]} for r in rows]

    def top_events(self, days: int = 7, limit: int = 10) -> list[dict]:
        since = date.today() - timedelta(days=days)
        rows = self.client.execute(
            'SELECT event_type, count() as cnt '
            'FROM events WHERE toDate(timestamp) >= %(since)s '
            'GROUP BY event_type ORDER BY cnt DESC LIMIT %(limit)s',
            {'since': since, 'limit': limit}
        )
        return [{'event': r[0], 'count': r[1]} for r in rows]
